import requests
import json
from bs4 import BeautifulSoup as soup
from selenium import webdriver


# Function to take screenshot of a website 
def get_screenshot(url):
    driver = webdriver.PhantomJS() # PhantomJS browser
    driver.get(url) # Load the URL in the PhantomJS browser
    screenshot = driver.get_screenshot_as_png() # Get screenshot as PNG

    return screenshot


# Function to parse HTML to extract title and meta description of a website 
def get_title_description(html): 
    try:
        soup_object = soup(html, 'lxml')
        title = soup_object.title.text
    except AttributeError:
        title = None
    
    try: 
        meta_description = soup_object.find('meta', attrs={'name':'description'})['content'] # Get the description from HTML
    except TypeError:
        meta_description = None

    return {'title': title, 'meta-description': meta_description}


